@mock.patch("django.core.management.commands.runserver.run")
@mock.patch("django.core.management.base.BaseCommand.check_migrations")
@mock.patch("django.core.management.base.BaseCommand.check")
def test_skip_checks(self, mocked_check, *mocked_objects):
    call_command(
        "runserver",
        use_reloader=False,
        skip_checks=True,
        stdout=self.output,
    )
    self.assertNotIn("Performing system checks...", self.output.getvalue())
    mocked_check.assert_not_called()

@mock.patch("django.core.management.commands.runserver.run")
@mock.patch("django.core.management.base.BaseCommand.check_migrations")
@mock.patch("django.core.management.base.BaseCommand.check")
def test_display_address_short_form_0(self, mocked_check, *mocked_objects):
    """
    When '0:8000' is passed, '0' should be expanded to '0.0.0.0' so the
    displayed address is 'http://0.0.0.0:8000/' (not 'http://0:8000/').
    This is consistent with the Django tutorial which says '0' is shorthand
    for '0.0.0.0'.
    """
    call_command(
        "runserver",
        "0:8000",
        use_reloader=False,
        skip_checks=True,
        stdout=self.output,
    )
    output = self.output.getvalue()
    self.assertIn("Starting development server at http://0.0.0.0:8000/", output)
